CreateEntityAtPositionMaybe = $C01E49
CurrentEntitySlot           = $1A42
CastEntitySpawnXTable       = $0E5E
CastEntitySpawnYTable       = $0E9A
Bg3VerticalScrollShadow     = $003B
CastSpawnVariantCounter     = $B4D3
CastSpawnVariantArgument    = $0A38
